// DataProvider — the single swappable seam between the UI and the data source.
//
// TODAY: reads the build-time JSON snapshot (dataset.json) generated by
//   scripts/generate-data.mjs. Fully static, GitHub Pages friendly.
// LATER: drop in a Neo4jDataProvider that returns the SAME shapes from live
//   Cypher queries — no component changes required. The JSON is already
//   graph-shaped (collections + graph.nodes/edges) to mirror the Neo4j model.

import dataset from "./dataset.json";

const byId = (arr) => Object.fromEntries(arr.map((x) => [x.id, x]));
const providersById = byId(dataset.providers);
const claimsById = byId(dataset.claims);
const veteransById = byId(dataset.veterans);
const rulesById = byId(dataset.rules);
const modelsById = byId(dataset.models);

export const meta = dataset.meta;
export const disclaimer = dataset.meta.disclaimer;

export function getKpis() { return dataset.kpis; }
export function getAnomalyBreakdown() { return dataset.anomalyBreakdown; }
export function getGraph() { return dataset.graph; }
export function getPeerBenchmark(key) { return dataset.peerBenchmarks[key]; }

export function getProvider(id) { return providersById[id] || null; }
export function getClaim(id) { return claimsById[id] || null; }
export function getVeteran(id) { return veteransById[id] || null; }

export function listProviders() { return dataset.providers; }

// Denormalized allegation for the detail view: joins provider, claim, veteran, model, rules.
export function getAllegation(id) {
  const a = dataset.allegations.find((x) => x.id === id);
  if (!a) return null;
  const provider = providersById[a.providerId] || null;
  const claim = a.claimId ? claimsById[a.claimId] : null;
  const veteran = claim ? veteransById[claim.veteranId] : null;
  return {
    ...a,
    provider,
    claim,
    veteran,
    model: a.modelId ? modelsById[a.modelId] : null,
    rules: (a.ruleIds || []).map((rid) => rulesById[rid]).filter(Boolean)
  };
}

// The work queue: light rows + filtering/sorting done in-memory (matches the
// no-code dynamic-search requirement; NL-search will map text -> these filters).
export function listAllegations(filters = {}) {
  let rows = dataset.allegations.map((a) => {
    const p = providersById[a.providerId];
    return {
      id: a.id, fwaType: a.fwaType, riskScore: a.riskScore, confidence: a.confidence,
      source: a.source, status: a.status, assignee: a.assignee, claimType: a.claimType,
      exposurePost: a.exposurePost, createdDate: a.createdDate,
      providerId: a.providerId, providerName: p ? p.name : "—",
      providerNpi: p ? p.npi : "", providerState: p ? p.state : ""
    };
  });
  const { fwaType, status, assignee, source, minRisk, query } = filters;
  if (fwaType) rows = rows.filter((r) => r.fwaType === fwaType);
  if (status) rows = rows.filter((r) => r.status === status);
  if (assignee) rows = rows.filter((r) => r.assignee === assignee);
  if (source) rows = rows.filter((r) => r.source === source);
  if (typeof minRisk === "number") rows = rows.filter((r) => r.riskScore >= minRisk);
  if (query) {
    const q = query.toLowerCase();
    rows = rows.filter((r) => [r.providerName, r.fwaType, r.providerNpi, r.id].join(" ").toLowerCase().includes(q));
  }
  rows.sort((a, b) => b.riskScore - a.riskScore);
  return rows;
}

// Provider claims (for drill-down lists).
export function listClaimsByProvider(providerId) {
  return dataset.claims.filter((c) => c.providerId === providerId);
}
